input.oldString:
onChange={(e) => {
  const value = e.target.value
  if (inputMode === 'token') {
    setFromAmount(value)
    if (value && fromTokenPrice > 0) {
      setUsdAmount((parseFloat(value) * fromTokenPrice).toFixed(2))
    } else {
      setUsdAmount('')
    }
  } else {
    setUsdAmount(value)
    if (value && fromTokenPrice > 0) {
      setFromAmount((parseFloat(value) / fromTokenPrice).toString())
    } else {
      setFromAmount('')
    }
  }
}}

input.newString:
onChange={(e) => {
  const value = sanitizeInput(e.target.value)
  if (inputMode === 'token') {
    if (!value || validateAmount(value, fromToken?.decimals || 18)) {
      setFromAmount(value)
      if (value && fromTokenPrice > 0) {
        setUsdAmount((parseFloat(value) * fromTokenPrice).toFixed(2))
      } else {
        setUsdAmount('')
      }
    }
  } else {
    if (!value || validateAmount(value, 2)) {
      setUsdAmount(value)
      if (value && fromTokenPrice > 0) {
        setFromAmount((parseFloat(value) / fromTokenPrice).toString())
      } else {
        setFromAmount('')
      }
    }
  }
}}

